function parseFormula(formula: string): Record<string, number> {
  const clean = formula.replace(/\s+/g, "");
  let index = 0;
  const parseGroup = (): Record<string, number> => {
    const counts: Record<string, number> = {};
    while (index < clean.length) {
      if (clean[index] === "(") {
        index += 1;
        const group = parseGroup();
        const multiplier = readNumber() || 1;
        Object.entries(group).forEach(([element, count]) => counts[element] = (counts[element] || 0) + count * multiplier);
      } else if (clean[index] === ")") {
        index += 1;
        break;
      } else {
        const match = clean.slice(index).match(/^([A-Z][a-z]?)/);
        if (!match) break;
        const element = match[1];
        index += element.length;
        const count = readNumber() || 1;
        counts[element] = (counts[element] || 0) + count;
      }
    }
    return counts;
  };
  const readNumber = () => {
    const match = clean.slice(index).match(/^(\d+(?:\.\d+)?)/);
    if (!match) return 0;
    index += match[1].length;
    return Number(match[1]);
  };
  return parseGroup();
}

function molarMass(formula: string) {
  return Object.entries(parseFormula(formula)).reduce((sum, [element, count]) => sum + (atomicWeights[element] || 0) * count, 0);
}

function parseComposition(input: string) {
  return input.split(/[,\n]+/).map((part) => {
    const [rawElement, rawValue] = part.split(":").map((item) => item?.trim());
    return rawElement && rawValue ? { element: rawElement, value: Number(rawValue) } : null;
  }).filter(Boolean) as Array<{ element: string; value: number }>;
}

function gcd(a: number, b: number): number {
  return b ? gcd(b, a % b) : Math.abs(a);
}

function empiricalFromComposition(input: string, mode: string) {
  const entries = parseComposition(input);
  const moleEntries = entries.map(({ element, value }) => ({ element, moles: value / (atomicWeights[element] || 1) }));
  const smallest = Math.min(...moleEntries.map((entry) => entry.moles));
  const ratios = moleEntries.map((entry) => {
    const raw = entry.moles / smallest;
    const candidates = [1, 2, 3, 4, 5, 6].map((multiplier) => ({ multiplier, error: Math.abs(raw * multiplier - Math.round(raw * multiplier)) }));
    const best = candidates.sort((a, b) => a.error - b.error)[0].multiplier;
    return { element: entry.element, count: Math.round(raw * best), multiplier: best, raw };
  });
  const lcm = ratios.reduce((current, ratio) => current * ratio.multiplier / gcd(current, ratio.multiplier), 1);
  const counts = moleEntries.map((entry) => ({ element: entry.element, count: Math.round((entry.moles / smallest) * lcm) }));
  const formula = counts.map(({ element, count }) => `${element}${count === 1 ? "" : count}`).join("");
  return {
    formula,
    mass: molarMass(formula),
    step: `${mode === "percent" ? "Treat each percent as grams" : "Use each entered mass in grams"}, divide by atomic mass, divide every mole value by the smallest mole value, then multiply to whole numbers.`,
  };
}

type Species = { formula: string; coefficient: number; side: "reactant" | "product"; mass: number };
function parseSpecies(raw: string, side: "reactant" | "product"): Species | null {
  const cleaned = raw.trim();
  if (!cleaned) return null;
  const match = cleaned.match(/^(\d*\.?\d*)\s*([A-Za-z0-9()]+)$/);
  if (!match) return null;
  const coefficient = match[1] ? Number(match[1]) : 1;
  const formula = match[2];
  return { formula, coefficient, side, mass: molarMass(formula) };
}

function parseEquation(equation: string) {
  const [left, right] = equation.replace(/=/g, "->").split("->");
  const reactants = (left || "").split("+").map((item) => parseSpecies(item, "reactant")).filter(Boolean) as Species[];
  const products = (right || "").split("+").map((item) => parseSpecies(item, "product")).filter(Boolean) as Species[];
  return [...reactants, ...products];
}

