function calculate(kind: Kind, mode: string, values: Record<string, string>): Result {
  if (kind === "ph") {
    if (mode === "hydroxide") {
      const oh = num(values, "hydroxide");
      const pOH = -log10(oh);
      return { label: "pOH", value: fmt(pOH, 3), detail: `pH at 25 C: ${fmt(14 - pOH, 3)}`, step: `pOH = -log10([OH-]) = -log10(${oh}) = ${fmt(pOH, 3)}. Then pH = 14 - pOH.`, cards: [{ label: "Hydroxide concentration", value: `${sci(oh)} M` }, { label: "Solution type", value: 14 - pOH < 7 ? "Acidic" : 14 - pOH === 7 ? "Neutral" : "Basic" }] };
    }
    if (mode === "fromPH") {
      const ph = num(values, "ph");
      const h = 10 ** -ph;
      return { label: "Hydrogen ion concentration", value: `${sci(h)} M`, detail: `pOH at 25 C: ${fmt(14 - ph, 3)}`, step: `[H+] = 10^(-pH) = 10^(-${ph}) = ${sci(h)} M.`, cards: [{ label: "pH", value: fmt(ph, 3) }, { label: "Category", value: ph < 7 ? "Acidic" : ph === 7 ? "Neutral" : "Basic" }] };
    }
    if (mode === "weakAcid") {
      const h = Math.sqrt(num(values, "ka") * num(values, "concentration"));
      const ph = -log10(h);
      return { label: "Weak acid pH", value: fmt(ph, 3), detail: `[H+] approx ${sci(h)} M`, step: `[H+] approx sqrt(Ka x C) = sqrt(${values.ka} x ${values.concentration}) = ${sci(h)} M, so pH = ${fmt(ph, 3)}.`, cards: [{ label: "Ka", value: values.ka }, { label: "Acid concentration", value: `${values.concentration} M` }] };
    }
    const h = num(values, "hydrogen");
    const ph = -log10(h);
    return { label: "pH", value: fmt(ph, 3), detail: `pOH at 25 C: ${fmt(14 - ph, 3)}`, step: `pH = -log10([H+]) = -log10(${h}) = ${fmt(ph, 3)}.`, cards: [{ label: "Hydrogen concentration", value: `${sci(h)} M` }, { label: "Category", value: ph < 7 ? "Acidic" : ph === 7 ? "Neutral" : "Basic" }] };
  }

  if (kind === "titration") {
    if (mode === "molarity") {
      const molarity = num(values, "knownM") * num(values, "knownV") / num(values, "unknownV");
      return { label: "Unknown molarity", value: `${fmt(molarity, 4)} M`, detail: "Assumes 1:1 stoichiometry", step: `M2 = M1 x V1 / V2 = ${values.knownM} x ${values.knownV} / ${values.unknownV} = ${fmt(molarity, 4)} M.`, cards: [{ label: "Titrant moles basis", value: `${fmt(num(values, "knownM") * num(values, "knownV") / 1000, 5)} mol` }, { label: "Unknown volume", value: `${values.unknownV} mL` }] };
    }
    if (mode === "equivalence") {
      const baseVolume = (num(values, "acidM") * num(values, "acidV") * num(values, "acidN")) / (num(values, "baseM") * num(values, "baseN"));
      return { label: "Base volume at equivalence", value: `${fmt(baseVolume, 3)} mL`, detail: "Acid equivalents equal base equivalents", step: `Vbase = Macid x Vacid x nacid / (Mbase x nbase) = ${values.acidM} x ${values.acidV} x ${values.acidN} / (${values.baseM} x ${values.baseN}) = ${fmt(baseVolume, 3)} mL.`, cards: [{ label: "Acid equivalents", value: `${fmt(num(values, "acidM") * num(values, "acidV") * num(values, "acidN") / 1000, 5)} eq` }, { label: "Base molarity", value: `${values.baseM} M` }] };
    }
    const volume = num(values, "knownM") * num(values, "knownV") / num(values, "unknownM");
    return { label: "Titrant volume needed", value: `${fmt(volume, 3)} mL`, detail: "Assumes 1:1 stoichiometry", step: `V2 = M1 x V1 / M2 = ${values.knownM} x ${values.knownV} / ${values.unknownM} = ${fmt(volume, 3)} mL.`, cards: [{ label: "Known moles", value: `${fmt(num(values, "knownM") * num(values, "knownV") / 1000, 5)} mol` }, { label: "Titrant concentration", value: `${values.unknownM} M` }] };
  }

  if (kind === "empiricalFormula") {
    const empirical = empiricalFromComposition(values.composition, mode);
    const ratio = Math.max(1, Math.round(num(values, "molarMass") / empirical.mass));
    const molecular = empirical.formula.replace(/([A-Z][a-z]?)(\d*)/g, (_, element, count) => `${element}${(Number(count || 1) * ratio) === 1 ? "" : Number(count || 1) * ratio}`);
    return { label: "Empirical formula", value: empirical.formula, detail: `Empirical formula mass: ${fmt(empirical.mass, 3)} g/mol`, step: empirical.step, cards: [{ label: "Molecular formula", value: Number.isFinite(ratio) ? molecular : "Add molar mass" }, { label: "Molecular ratio", value: `${ratio}x` }] };
  }

  if (kind === "percentYield") {
    if (mode === "theoretical") {
      const grams = num(values, "moles") * num(values, "molarMass");
      return { label: "Theoretical yield", value: `${fmt(grams, 3)} g`, detail: "Product moles converted to grams", step: `Theoretical yield = moles x molar mass = ${values.moles} x ${values.molarMass} = ${fmt(grams, 3)} g.`, cards: [{ label: "Moles", value: `${values.moles} mol` }, { label: "Molar mass", value: `${values.molarMass} g/mol` }] };
    }
    const yieldPercent = num(values, "actual") / num(values, "theoretical") * 100;
    return { label: "Percent yield", value: `${fmt(yieldPercent, 2)}%`, detail: yieldPercent > 100 ? "Check for wet product, impurity, or calculation error" : yieldPercent >= 90 ? "Excellent yield" : yieldPercent >= 70 ? "Good yield" : "Low yield", step: `Percent yield = actual / theoretical x 100 = ${values.actual} / ${values.theoretical} x 100 = ${fmt(yieldPercent, 2)}%.`, cards: [{ label: "Actual yield", value: `${values.actual} g` }, { label: "Theoretical yield", value: `${values.theoretical} g` }] };
  }

  const species = parseEquation(values.equation);
  const known = species.find((item) => item.formula === values.knownFormula) || species[0];
  const knownMoles = values.knownUnit === "mol" ? num(values, "knownAmount") : num(values, "knownAmount") / known.mass;
  const normalized = knownMoles / known.coefficient;
  const lines = species.map((item) => `${item.formula}: ${fmt(normalized * item.coefficient, 4)} mol, ${fmt(normalized * item.coefficient * item.mass, 3)} g`);
  if (mode === "limiting") {
    const second = species.find((item) => item.formula === values.secondFormula) || species[1] || known;
    const secondMoles = values.secondUnit === "mol" ? num(values, "secondAmount") : num(values, "secondAmount") / second.mass;
    const firstRatio = knownMoles / known.coefficient;
    const secondRatio = secondMoles / second.coefficient;
    const limiting = firstRatio <= secondRatio ? known : second;
    return { label: "Limiting reagent", value: limiting.formula, detail: `${firstRatio <= secondRatio ? second.formula : known.formula} is in excess`, step: `Compare moles divided by coefficients: ${known.formula} = ${fmt(firstRatio, 4)}, ${second.formula} = ${fmt(secondRatio, 4)}. The smaller value is limiting.`, cards: [{ label: known.formula, value: `${fmt(knownMoles, 4)} mol available` }, { label: second.formula, value: `${fmt(secondMoles, 4)} mol available` }], extra: lines };
  }
  return { label: "Stoichiometric scale factor", value: fmt(normalized, 4), detail: `Based on ${values.knownAmount} ${values.knownUnit} of ${known.formula}`, step: `Convert ${known.formula} to moles, divide by its coefficient (${known.coefficient}), then multiply every balanced coefficient by that factor.`, cards: [{ label: "Known moles", value: `${fmt(knownMoles, 4)} mol` }, { label: "Known molar mass", value: `${fmt(known.mass, 3)} g/mol` }], extra: lines };
}

function ChemistryTable({ table }: { table: PageConfig["table"] }) {
  return (
    <section className="bg-card border border-border rounded-2xl p-6 shadow-sm mb-8">
      <h2 className="text-2xl font-bold text-foreground mb-4">{table.title}</h2>
      <div className="overflow-x-auto rounded-xl border border-border">
        <table className="w-full text-sm">
          <thead><tr className="bg-muted/80">{table.headers.map((header) => <th key={header} className="text-left font-bold text-foreground px-4 py-3 whitespace-nowrap">{header}</th>)}</tr></thead>
          <tbody>{table.rows.map((row, index) => <tr key={`${row[0]}-${index}`} className={index % 2 === 0 ? "bg-background" : "bg-muted/35"}>{row.map((cell, cellIndex) => <td key={`${cell}-${cellIndex}`} className="px-4 py-3 text-muted-foreground whitespace-nowrap">{cell}</td>)}</tr>)}</tbody>
        </table>
      </div>
    </section>
  );
}

function LinkList({ title, items }: { title: string; items: Array<string | { label: string; href: string }> }) {
  return (
    <section className="bg-card border border-border rounded-2xl p-6 shadow-sm mb-8">
      <h2 className="text-2xl font-bold text-foreground mb-4">{title}</h2>
      <div className="flex flex-wrap gap-2">
        {items.map((item) => {
          const label = typeof item === "string" ? item : item.label;
          const href = typeof item === "string" ? undefined : item.href;
          const className = "rounded-full border border-border bg-muted/50 px-3 py-1.5 text-sm font-semibold text-muted-foreground hover:text-primary transition-colors";
          return href ? <a key={label} href={href} className={className}>{label}</a> : <span key={label} className={className}>{label}</span>;
        })}
      </div>
    </section>
  );
}

function PHScale({ result }: { result: Result }) {
  const phMatch = result.value.match(/-?\d+(?:\.\d+)?/);
  const ph = phMatch ? Math.min(14, Math.max(0, Number(phMatch[0]))) : 7;
  return (
    <div className="mt-4 rounded-xl border border-border bg-accent/40 p-4">
      <div className="flex justify-between text-xs font-bold text-muted-foreground mb-2"><span>Acidic</span><span>Neutral</span><span>Basic</span></div>
      <div className="relative h-3 rounded-full bg-gradient-to-r from-red-500 via-yellow-300 to-blue-600">
        <span className="absolute -top-1 h-5 w-1.5 rounded-full bg-foreground" style={{ left: `calc(${(ph / 14) * 100}% - 3px)` }} />
      </div>
      <div className="mt-2 flex justify-between text-[10px] text-muted-foreground"><span>0</span><span>7</span><span>14</span></div>
    </div>
  );
}

